import{_ as a,o as i,c as t,a1 as r}from"./chunks/framework.BX4nIuL2.js";const h=JSON.parse('{"title":"CNC","description":"","frontmatter":{},"headers":[],"relativePath":"courses/fab-course/doc/8CNC_manufacture/cnctype.md","filePath":"courses/fab-course/doc/8CNC_manufacture/cnctype.md"}'),l={name:"courses/fab-course/doc/8CNC_manufacture/cnctype.md"};function n(o,e,c,s,d,m){return i(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="cnc" tabindex="-1">CNC <a class="header-anchor" href="#cnc" aria-label="Permalink to &quot;CNC&quot;">​</a></h1><p>CNC (Computer Numerical Control ) is a term that refers to computer guided machining. In computer we need add a level of detail, speed and precision that saves a great deal of time for high-fidelity prototyping. CNC IS a subtractive digital method that removes material from a solid block or sheet of material in a rapid fashion.</p><p>Depend on process, we can define the type as following:Lathing(Turning) ,Drilling,Milling, Grinding,etc.</p><p>During manufacture, first need rough process(remove most of material and get the general shape) and then need finish process(remove the last material slowly to keep the high quality of surface).</p><p><img src="https://gitlab.com/picbed/bed/uploads/c96451f7fe80fa15c12c0006de570f83/machine.png" alt=""></p><p><strong>The advantage of CNC as following</strong></p><ul><li>Material selection is very broad and including plastic,metal,foam and wood;</li><li>Material cost would much less than additive manufacturing;</li><li>Surface quality can be extremely high;</li><li>Precision is extremely highl;</li></ul><p><strong>The limitation of CNC as following</strong></p><ul><li>Require special training;</li><li>Require knowledge of fixturing;</li><li>Require knowledge of Computer Aided Manufacturing software;</li><li>Fine features require very fine cutters.</li></ul><h2 id="_1-turning" tabindex="-1">1.Turning <a class="header-anchor" href="#_1-turning" aria-label="Permalink to &quot;1.Turning&quot;">​</a></h2><p><img src="https://gitlab.com/picbed/bed/uploads/8126eb998091ce3098f953d2a00b7a3f/lathe-use.jpeg" alt=""></p><p>Turing usual use Lathe machine to run a subtractive manufacturing process. Normal processes various rotary surfaces (inner and outer cylinders, conical surfaces, shaped rotary surfaces, etc.) . The cutter would feed and cut material one layer by one layer.</p><p><img src="https://gitlab.com/picbed/bed/uploads/f50cdd78de92a1e2094d638175c3e5a6/what-is-lathe-machine.jpeg" alt=""> Traditional lathe machine&#39;s main motion is the rotation of spindle from motor and the feed motion (linear movement)</p><p>The main components are following:1.headstock; 2.knife holder; 3.tailstock; 4.bed; 5.right bed legs; 6.light bar; 7.screw; 8.sliding box; 9.left leg; 10.feeding box; 11.hanging wheel mechanism <img src="https://gitlab.com/picbed/bed/uploads/6e2492cf2cef00b856eacd5240c5b11c/white-board-threading.gif" alt=""> Modern turning centres use even more accurate ball screws, these are actuated by motors controlled by PLC ( Programmable Logic Controller). It would automate produce part according to CAD file.</p><h2 id="_2-drilling" tabindex="-1">2.Drilling <a class="header-anchor" href="#_2-drilling" aria-label="Permalink to &quot;2.Drilling&quot;">​</a></h2><p>Drilling is a cutting process that uses drill bit of various sizes to cut a hole of circular-section in solid materials like metal, plastic, wood, rocks etc.</p><p><img src="https://gitlab.com/picbed/bed/uploads/95891f2652114bd0c77c544da889951a/drillingmachine.png" alt=""></p><p>There are some types as following:</p><p><img src="https://gitlab.com/picbed/bed/uploads/e4a4503fe475d9ac26b0e5997e61e930/WX20211201-225758.png" alt=""></p><h2 id="_3-milling" tabindex="-1">3.Milling <a class="header-anchor" href="#_3-milling" aria-label="Permalink to &quot;3.Milling&quot;">​</a></h2><p>CNC milling is a subtractive manufacturing process. It starts by fixturing a block of metal or plastic material inside the CNC mill. Using G-code, the CNC machine is programmed to rapidly mill out parts from the block of raw material.</p><p><img src="https://gitlab.com/picbed/bed/uploads/d63917e52d0e306d5acd5b470854162e/milling-copy-on-part.gif" alt=""></p><p>3- and 5-axis CNC machines are equipped with various toolsets to maximize efficiency and production speed. There are many different kinds of cutter as following<a href="https://fractory.com/milling-cutters-and-tools/" target="_blank" rel="noreferrer">(End mill,Face mill,Ball cutter,Slab mill,Side-and-face cutter,Involute gear cutter,Fly cutter,Hollow mill,Shell mill,Roughing end mill,Dovetail cutter,Wood ruff cutter)</a>.</p><p>End cutter and face cutter is often used.The difference between end milling and face milling is that an end mill uses both the end and the sides of the cutter, whereas face milling is used for horizontal cutting. <img src="https://gitlab.com/picbed/bed/uploads/ea9c202db90657056209fcbcc1469ca2/millingcutter.png" alt=""><a href="https://www.mechanicalbooster.com/2018/08/types-of-milling-cutters-used-in-machining-process.html" target="_blank" rel="noreferrer">The picture reference from mechanical booster</a></p><h2 id="_4-grinding" tabindex="-1">4. Grinding <a class="header-anchor" href="#_4-grinding" aria-label="Permalink to &quot;4. Grinding&quot;">​</a></h2><p><a href="https://www.allied-material.co.jp/en/products/diamond/knowledge/various_grinding.html" target="_blank" rel="noreferrer">reference allied material</a></p><h2 id="_5-axis-machine" tabindex="-1">5- Axis machine <a class="header-anchor" href="#_5-axis-machine" aria-label="Permalink to &quot;5- Axis machine&quot;">​</a></h2><p>Those are heavy industry machine primarily developed to cut metal. Tool changers allow the mchine selectively to performance different types of machining operations ,including milling ,drilling and tapping. These production machines are intended to produce manyidentical parts to close tolerances and specification.The high cost ,large footprint,and power requirements restrict this type of equipment to industrial environment.</p><p><img src="https://gitlab.com/picbed/bed/uploads/f384303296048f22632949d503f8f30c/5-2-indexed-milling.gif" alt=""></p><h2 id="reference" tabindex="-1">Reference <a class="header-anchor" href="#reference" aria-label="Permalink to &quot;Reference&quot;">​</a></h2><ul><li><a href="https://www.protolabs.com/services/cnc-machining/cnc-milling/" target="_blank" rel="noreferrer">Protolabs</a></li><li><a href="https://www.nexpcb.com/capabilities/mechanical-engineering" target="_blank" rel="noreferrer">NexPCB</a></li><li><a href="https://www.allied-material.co.jp/en/products/diamond/knowledge/various_grinding.html" target="_blank" rel="noreferrer">Grinding: allied material</a></li><li><a href="https://www.autodesk.com/solutions/cnc-programming" target="_blank" rel="noreferrer">CNC-Programming-Autodesk</a></li><li><a href="https://knowledge.autodesk.com/zh-hans/support/powermill/getting-started/caas/simplecontent/content/powermill-getting-started-tutorial.html" target="_blank" rel="noreferrer">Powermill-Autodesk</a></li><li><a href="https://zhuanlan.zhihu.com/p/34438936" target="_blank" rel="noreferrer">UG NC coding </a></li></ul>',31)])])}const u=a(l,[["render",n]]);export{h as __pageData,u as default};
